 /*
+ * Get ficticious geometry from total sectors.
+ */
+static void
+od_get_geometry(total, cp, hp, sp)
+	u_int32_t total;
+	u_int16_t *cp;
+	u_char *hp;
+	u_char *sp;
+{
+	u_int16_t cyls;
+	u_char heads;
+	u_char sectors;
+
+	heads = 64;
+	sectors = 32;
+
+	if (total != 0) {
+		cyls = total / (64 * 32);
+		while (cyls >= 1024) {
+			if (heads < 128) {
+				heads *= 2;
+			} else {
+				heads = 255;
+				sectors = 63;
+				cyls = total / (heads * sectors);
+				break;
+			}
+			cyls = total / (heads * sectors);
+		}
+		if (total > (cyls * heads * sectors))
+			cyls++;
+	} else
+		cyls = 0;
+
+	*cp = cyls;
+	*hp = heads;
+	*sp = sectors;
+}
